+fn push_bounded<T>(queue: &mut Vec<T>, item: T, limit: usize) {
+    if queue.len() >= limit {
+        let overflow = queue.len() - limit + 1;
+        queue.drain(..overflow);
+    }
+    queue.push(item);
+}
